#include<bits/stdc++.h>
using namespace std;
int n,b[4000010],cnt,sumf;
int lowbit(int x)
{
    return x&-x;
}
struct BIT
{
    int c[4000010];
    void update(int x,int v)
    {
        for(int i=x;i<=cnt;i+=lowbit(i))
        {
            c[i]+=v;
        }
    }
}s1,s2;
int query(int x)
{
    if(x<1||x>cnt)
    {
        return 0;
    }
    int ans1=0,ans2=sumf;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans1+=s1.c[i];
        ans2+=s2.c[i];
    }
    return min(ans1,ans2);
}
struct node
{
    bool type;
    int t,v,op;
}e[4000010];
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&e[i].op);
        if(e[i].op==1)
        {
            cnt++;
            int tmp;
            scanf("%d",&tmp);
            e[i].type=tmp;
            scanf("%d%d",&e[i].t,&e[i].v);
            b[cnt]=e[i].t;
        }
        else
        {
            int x;
            scanf("%d",&x);
            e[i]=e[x];
            e[i].op=2;
            e[i].v=-e[i].v;
        }
    }
    sort(b+1,b+1+cnt);
    cnt=unique(b+1,b+1+cnt)-b-1;
    for(int i=1;i<=n;i++)
    {
        e[i].t=lower_bound(b+1,b+1+cnt,e[i].t)-b;
    }
    for(int i=1;i<=n;i++)
    {
        if(e[i].type==0)
        {
            s1.update(e[i].t,e[i].v);
        }
        else
        {
            s2.update(e[i].t+1,-e[i].v);
            sumf+=e[i].v;
        }
        int x1=0,sum=-sumf;
        for(int j=21;j>=0;j--)
        {
            int tmp=x1|(1<<j),tmp1;
            tmp1=sum+s1.c[tmp]-s2.c[tmp];
            if(tmp<=cnt&&tmp1<=0)
            {
                sum=tmp1;
                x1=tmp;
            }
        }
        int ans1=query(x1),x2=x1+1,ans2=query(x2);
        if(ans1<=0&&ans2<=0)
        {
            printf("Peace\n");
        }
        else if(ans1>ans2)
        {
            printf("%d %d\n",b[x1],ans1*2);
        }
        else
        {
            int p=0,sum=sumf;
            for(int j=21;j>=0;j--)
            {
                int tmp=p|(1<<j),tmp1;
                tmp1=sum+s2.c[tmp];
                if(tmp<=cnt&&tmp1>=ans2)
                {
                    p=tmp;
                    sum=tmp1;
                }
            }
            printf("%d %d\n",b[p],sum*2);
        }
    }
    return 0;
}
